const body = $json.body ?? $json;
const topic = String(body.topic ?? '').trim();
const startDate = String(body.start_date ?? '').trim();
const endDate = String(body.end_date ?? '').trim();

if (!topic) {
  throw new Error('topic is required');
}
if (!/^\d{4}-\d{2}-\d{2}$/.test(startDate) || !/^\d{4}-\d{2}-\d{2}$/.test(endDate)) {
  throw new Error('start_date and end_date must be YYYY-MM-DD');
}

const start = new Date(`${startDate}T00:00:00.000Z`);
const end = new Date(`${endDate}T23:59:59.999Z`);
if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
  throw new Error('Invalid date values supplied');
}
if (start > end) {
  throw new Error('start_date must be <= end_date');
}

const now = new Date();
const endDateOnly = new Date(`${endDate}T00:00:00.000Z`);
const nowDateOnly = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
if (endDateOnly > nowDateOnly) {
  throw new Error('end_date cannot be in the future');
}

const maxRangeDays = 30;
const diffDays = Math.floor((endDateOnly - new Date(`${startDate}T00:00:00.000Z`)) / (1000 * 60 * 60 * 24));
if (diffDays > maxRangeDays) {
  throw new Error('date range must be 30 days or less');
}

const runId = `run_${Math.random().toString(16).slice(2, 12)}`;
const startedAt = new Date().toISOString();

return [{
  json: {
    run_id: runId,
    started_at: startedAt,
    input: {
      topic,
      start_date: startDate,
      end_date: endDate
    },
    source: {
      id: 'hackernews_algolia',
      endpoint: 'https://hn.algolia.com/api/v1/search_by_date',
      tags: 'story'
    },
    ingestion_query: {
      query: topic,
      tags: 'story',
      numericFilters: `created_at_i>=${Math.floor(start.getTime() / 1000)},created_at_i<=${Math.floor(end.getTime() / 1000)}`,
      hitsPerPage: 200
    }
  }
}];

const runId = $json.run_id;
const startedAt = $json.started_at;
const input = $json.input;
const source = $json.source;

const responsePayload = $json;
const rawHits = Array.isArray(responsePayload.hits) ? responsePayload.hits : [];
const hitsCount = Number(responsePayload.nbHits ?? rawHits.length ?? 0);

const canonicalArticles = [];
const validationIssues = [];

for (let i = 0; i < rawHits.length; i += 1) {
  const hit = rawHits[i] ?? {};
  const title = hit.title ?? hit.story_title ?? null;
  const url = hit.url ?? hit.story_url ?? null;
  const publishedAt = hit.created_at ?? null;
  const objectId = hit.objectID ?? null;

  const missingFields = [];
  if (!title) missingFields.push('title');
  if (!publishedAt) missingFields.push('published_at');
  if (!objectId) missingFields.push('object_id');

  if (missingFields.length > 0) {
    validationIssues.push({
      hit_index: i,
      object_id: objectId,
      missing_fields: missingFields
    });
    continue;
  }

  canonicalArticles.push({
    article_id: `${source.id}:${objectId}`,
    title,
    url,
    published_at: publishedAt,
    source: source.id
  });
}

const countsByDay = {};
for (const article of canonicalArticles) {
  if (!article.published_at) continue;
  const parsed = new Date(article.published_at);
  if (Number.isNaN(parsed.getTime())) continue;
  const day = parsed.toISOString().slice(0, 10);
  countsByDay[day] = (countsByDay[day] ?? 0) + 1;
}

const dailyCounts = Object.keys(countsByDay)
  .sort()
  .map((day) => ({ day, article_count: countsByDay[day] }));

return [{
  json: {
    run_id: runId,
    started_at: startedAt,
    input,
    stages: {
      ingestion: {
        source: source.id,
        requested_at: new Date().toISOString(),
        query: input.topic,
        hits_count: hitsCount,
        raw_hits: rawHits
      },
      normalization: {
        canonical_articles: canonicalArticles,
        validation_issues: validationIssues,
        valid_count: canonicalArticles.length,
        invalid_count: validationIssues.length
      },
      aggregation: {
        daily_counts: dailyCounts,
        total_days: dailyCounts.length
      }
    }
  }
}];
